}

    .send-btn:hover:not(:disabled) {
        background: #148567;
    }

    .send-btn:disabled {
        background: #3c3f44;
        color: #6b6d72;
        cursor: not-allowed;
    }

/* ───── Thread Panel ───── */

.thread-panel {
    width: 25%;
    min-width: 280px;
    background: #1a1d21;
    border-left: 1px solid #2c2d30;
    display: flex;
    flex-direction: column;
