}

    .close-thread-btn:hover {
        background: #2c2d30;
        color: #fff;
    }

.thread-root-quote {
    padding: 12px 16px;
    border-bottom: 1px solid #2c2d30;
    background: #222529;
    flex-shrink: 0;
}

    .thread-root-quote .author {
        font-size: 0.85rem;
