@code {
    private const int PageSize = 30;

    private IJSObjectReference? _jsModule;
    private ElementReference _messageListRef;
    private ElementReference _threadListRef;

    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;

    private List<Message>? _messages;
    private int _messageSkip;
    private bool _loadingOlder;
    private bool _allOlderLoaded;

    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private string _newMessageText = "";

    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadMessages;
    private string _threadReplyText = "";

    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Pages/Chat.razor.js");
        }
    }

    // ───── Channel Selection ─────

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _messageSkip = 0;
        _allOlderLoaded = false;
        _messages = null;

        await ChatService.MarkChannelReadAsync(channel.Id);

        var messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = messages;
        _messageSkip = messages.Count;

        await BuildThreadSummaries();
        await RefreshChannelList();

        StateHasChanged();
        await ScrollMessagesToBottomAsync();
    }

    private async Task RefreshChannelList()
    {
        _channels = await ChatService.GetChannelsAsync();
        _activeChannel = _channels.FirstOrDefault(c => c.Id == _activeChannelId);
    }

    // ───── Message Scrolling & Pagination ─────

    private async Task HandleMessageScrollAsync()
    {
        if (_loadingOlder || _allOlderLoaded || _jsModule is null || _activeChannelId is null)
            return;

        var isTop = await _jsModule.InvokeAsync<bool>("isScrolledToTop", _messageListRef);
        if (!isTop) return;

        _loadingOlder = true;
        StateHasChanged();

        var prevHeight = await _jsModule.InvokeAsync<double>("getScrollHeight", _messageListRef);
        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messageSkip, PageSize);

        if (older.Count == 0)
        {
            _allOlderLoaded = true;
        }
        else
        {
            _messages = [..older, ..(_messages ?? [])];
            _messageSkip += older.Count;
            await BuildThreadSummaries();
        }

        _loadingOlder = false;
        StateHasChanged();

        // Preserve scroll position after prepending older messages
        await Task.Yield();
        if (_jsModule is not null)
        {
            await _jsModule.InvokeVoidAsync("preserveScrollAfterPrepend", _messageListRef, prevHeight);
        }
    }

    private async Task ScrollMessagesToBottomAsync()
    {
        await Task.Yield();
        if (_jsModule is not null)
        {
            await _jsModule.InvokeVoidAsync("scrollToBottom", _messageListRef);
        }
    }

    private async Task ScrollThreadToBottomAsync()
    {
        await Task.Yield();
        if (_jsModule is not null)
        {
            await _jsModule.InvokeVoidAsync("scrollToBottom", _threadListRef);
        }
    }

    // ───── Sending Messages ─────

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _messages ??= [];
        _messages.Add(sent);
        _messageSkip++;
        _newMessageText = "";

        StateHasChanged();
        await ScrollMessagesToBottomAsync();
    }

    private async Task HandleMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // ───── Reactions ─────

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Refresh the message list to show updated reactions
        if (_activeChannelId is not null && _messages is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messageSkip);
            _messages = refreshed;
        }

        // Refresh thread if open
        if (_threadOpen && _threadRootMessage is not null)
        {
            _threadMessages = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    // ───── Thread Panel ─────

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadOpen = true;
        _threadReplyText = "";

        StateHasChanged();
        await ScrollThreadToBottomAsync();
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = null;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootMessage is null || _activeChannelId is null)
            return;

        var reply = await ChatService.SendMessageAsync(
            _activeChannelId.Value, _threadReplyText.Trim(), _threadRootMessage.Id);

        _threadMessages ??= [];
        _threadMessages.Add(reply);
        _threadReplyText = "";

        await BuildThreadSummaries();
        StateHasChanged();
        await ScrollThreadToBottomAsync();
    }

    private async Task HandleThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ───── Thread Summaries ─────

    private async Task BuildThreadSummaries()
    {
        _threadSummaries.Clear();
        if (_messages is null) return;

        // Identify root messages that have replies (ReplyToId == null and other messages reference them)
        var rootIds = _messages
            .Where(m => m.ReplyToId is not null)
            .Select(m => m.ReplyToId!.Value)
            .Distinct()
            .ToList();

        foreach (var rootId in rootIds)
        {
            var thread = await ChatService.GetThreadAsync(rootId);
            if (thread.Count > 0)
            {
                _threadSummaries[rootId] = new ThreadSummary(
                    rootId,
                    thread.Count,
                    thread.Max(t => t.SentAt));
            }
        }
    }

    private ThreadSummary? GetThreadSummary(int messageId)
    {
        return _threadSummaries.GetValueOrDefault(messageId);
    }

    // ───── Helpers ─────

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 10 => "just now",
            < 60 => $"{(int)diff.TotalSeconds}s ago",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40
            ? string.Concat(description.AsSpan(0, 37), "...")
            : description;
    }

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            await _jsModule.DisposeAsync();
        }
    }
}

