toolArgs.file_text:
/* ───── Layout Shell ───── */

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    background: #1a1d21;
    color: #d1d2d3;
}

/* ───── Channel Sidebar ───── */

.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #19171d;
    border-right: 1px solid #2c2d30;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 12px;
    border-bottom: 1px solid #2c2d30;
}

    .sidebar-header h5 {
        margin: 0;
        color: #fff;
        font-size: 1.1rem;
        font-weight: 700;
    }

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    position: relative;
    transition: background 0.15s;
    border-left: 3px solid transparent;
}

    .channel-item:hover {
        background: #27242c;
    }

    .channel-item.active {
        background: #1164a3;
        border-left-color: #fff;
    }

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #fff;
    margin-bottom: 2px;
}

.channel-desc {
    font-size: 0.78rem;
    color: #9a9b9e;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    position: absolute;
    top: 10px;
    right: 12px;
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 10px;
    min-width: 20px;
    text-align: center;
}

/* ───── Main Message Area ───── */

.message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    transition: width 0.2s ease;
}

    .message-area.full-width {
        width: 80%;
    }

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #2c2d30;
    background: #1a1d21;
    flex-shrink: 0;
}

    .message-header h5 {
        margin: 0 0 2px;
        color: #fff;
        font-size: 1.05rem;
        font-weight: 700;
    }

.channel-description {
    font-size: 0.82rem;
    color: #9a9b9e;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #6b6d72;
    font-size: 1.1rem;
}

/* ───── Message List ───── */

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.loading-indicator {
    text-align: center;
    padding: 8px;
    color: #6b6d72;
    font-size: 0.85rem;
}

.message-bubble {
    position: relative;
    padding: 6px 12px;
    border-radius: 6px;
    transition: background 0.1s;
}

    .message-bubble:hover {
        background: #222529;
    }

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.92rem;
    color: #fff;
}

.timestamp {
    font-size: 0.75rem;
    color: #6b6d72;
}

.message-content {
    font-size: 0.93rem;
    line-height: 1.45;
    color: #d1d2d3;
    word-wrap: break-word;
}

/* ───── Reactions ───── */

.reactions-row {
    display: flex;
    gap: 6px;
    margin-top: 6px;
    flex-wrap: wrap;
}

.reaction-badge {
    background: #2c2d30;
    border: 1px solid #3c3f44;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.82rem;
    cursor: pointer;
    color: #d1d2d3;
    transition: background 0.15s, border-color 0.15s;
    display: inline-flex;
    align-items: center;
    gap: 4px;
}

    .reaction-badge:hover {
        background: #3c3f44;
        border-color: #565860;
    }

/* ───── Thread Link ───── */

.thread-link {
    background: none;
    border: none;
    color: #1d9bd1;
